    setTimeout(() => {
      const frame = captureMockFrame()
      if (frame) {
        mockFramesRef.current.push(frame)
        mockPerQuestionFramesRef.current.push(frame)
      }
    }, 500)
    // Then every 4 seconds (matching quick practice interval)
    mockFrameIntervalRef.current = setInterval(() => {
      const frame = captureMockFrame()
